UPDATE tnt_outbox
   SET status = 'PENDING',
       retry_count = #{retryCount},
       last_error = #{error}
 WHERE id = #{id}

UPDATE tnt_outbox
   SET status = 'FAILED',
       processed_at = now(),
       retry_count = #{retryCount},
       last_error = #{error}
 WHERE id = #{id}
